// Verify WaSender secret + extract the message. Two MEC groups are processed (set their JIDs in env):
//   MEC_ORDERS_GROUP_JID = the daily orders/chat group  -> group_type 'orders'
//   MEC_DOCS_GROUP_JID    = the invoices/documents group -> group_type 'docs'
// Direct messages stay group_type 'dm'. Any OTHER group is ignored. In a group the real author is
// key.participant (the sender) — that person is the SALESPERSON who brought the order.
const crypto = require('crypto');
const secret = $env.WASENDER_WEBHOOK_SECRET || '';
const ordersJid = String($env.MEC_ORDERS_GROUP_JID || '').trim();
const docsJid = String($env.MEC_DOCS_GROUP_JID || '').trim();
const item = $input.first().json;
const headers = item.headers || {};
const body = item.body || item;

const sig = headers['x-webhook-signature'] || headers['X-Webhook-Signature'] || '';
let verified = false;
try { const hmac = crypto.createHmac('sha256', secret).update(JSON.stringify(body)).digest('hex'); verified = Boolean(sig && (sig === secret || sig === hmac)); } catch (e) { verified = false; }

const ev = body.data || body;
const msg = ev.messages || ev.message || (ev.event === 'messages.upsert' ? ev.data : null) || ev;
const m = Array.isArray(msg) ? msg[0] : msg;
if (!m) return [];
if (m.key && m.key.fromMe) return [];            // ignore our own outgoing

const remoteJid = (m.key && m.key.remoteJid) || m.from || m.chatId || ev.from || '';
if (/status@broadcast/.test(remoteJid)) return [];
const isGroup = /@g\.us/.test(remoteJid);

let group_type = 'dm';
if (isGroup) {
  if (ordersJid && remoteJid === ordersJid) group_type = 'orders';
  else if (docsJid && remoteJid === docsJid) group_type = 'docs';
  else group_type = 'unknown';                    // record it so its group_jid shows in the inbox (setup), but don't process as an order/doc
}

const participant = (m.key && m.key.participant) || m.participant || '';
const senderJid = isGroup ? participant : remoteJid;
const senderPhone = String(senderJid).replace(/@s\.whatsapp\.net$/, '').replace(/@g\.us$/, '');
const senderName = m.pushName || ev.pushName || '';

let content = m.message || {};
// Unwrap WhatsApp envelopes so the real content is seen — forwarded PDFs/images-with-caption,
// disappearing (ephemeral) and view-once messages all nest the actual message one level down.
content = (content.ephemeralMessage && content.ephemeralMessage.message)
  || (content.viewOnceMessage && content.viewOnceMessage.message)
  || (content.viewOnceMessageV2 && content.viewOnceMessageV2.message)
  || (content.documentWithCaptionMessage && content.documentWithCaptionMessage.message)
  || content;
const docMsg = content.documentMessage || null;
const imgMsg = content.imageMessage || null;
// For a document the file name/title is the best signal of what it is (e.g. "فاتورة ... 389.pdf").
const text = content.conversation
  || (content.extendedTextMessage && content.extendedTextMessage.text)
  || (imgMsg && imgMsg.caption)
  || (docMsg && (docMsg.caption || docMsg.title || docMsg.fileName))
  || m.text || m.body || '';
let type = 'text';
if (imgMsg || m.type === 'image') type = 'image';
else if (docMsg) type = 'document';
else if (content.audioMessage) type = 'audio';
else if (content.reactionMessage) type = 'reaction';

// A reaction (e.g. a ✅ on the order message) carries the emoji + the id of the message it reacts to.
const reaction = content.reactionMessage || {};
const reaction_emoji = reaction.text || '';
const reaction_target = (reaction.key && reaction.key.id) || '';

// Drop only pure system/encryption noise (key exchange, protocol). EVERYTHING else — including ordinary
// chatter — is saved so the admin can audit exactly what JARVIS read; chatter is classified intent=other
// and the order guard means it never becomes an order.
const _realKeys = Object.keys(content).filter(k => !['messageContextInfo', 'senderKeyDistributionMessage', 'protocolMessage'].includes(k));
if (!text && _realKeys.length === 0) return [];

// Quoted/replied message id — threads an approval / rejection / quantity adjustment back to the order.
const ctx = (content.extendedTextMessage && content.extendedTextMessage.contextInfo)
  || (imgMsg && imgMsg.contextInfo)
  || (docMsg && docMsg.contextInfo) || {};
const quoted_message_id = ctx.stanzaId || ctx.quotedMessageId || '';

return [{ json: {
  message_id: (m.key && m.key.id) || m.id || `${remoteJid}-${m.messageTimestamp || ''}`,
  group_jid: isGroup ? remoteJid : '',
  group_type,
  phone: senderPhone,
  push_name: senderName,
  salesperson: senderName,
  body: text,
  message_type: type,
  media_url: (docMsg && docMsg.url) || (imgMsg && imgMsg.url) || m.mediaUrl || '',
  quoted_message_id,
  reaction_emoji,
  reaction_target,
  verified,
  raw: body
}}];

